/// Generate the outbox table UP migration SQL.
pub fn generate_outbox_up_migration() -> String {
    r#"-- Outbox table for reliable event publishing
-- Auto-generated by k1s0-codegen event-codegen

CREATE TABLE IF NOT EXISTS outbox (
    id            BIGSERIAL PRIMARY KEY,
    topic         TEXT        NOT NULL,
    partition_key TEXT        NOT NULL,
    payload       BYTEA       NOT NULL,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    published_at  TIMESTAMPTZ,
    retry_count   INT         NOT NULL DEFAULT 0,
    last_error    TEXT
);

CREATE INDEX idx_outbox_unpublished
    ON outbox (created_at)
    WHERE published_at IS NULL;
"#
    .to_string()
}

/// Generate the outbox table DOWN migration SQL.
pub fn generate_outbox_down_migration() -> String {
    r#"-- Rollback outbox table
-- Auto-generated by k1s0-codegen event-codegen

DROP INDEX IF EXISTS idx_outbox_unpublished;
DROP TABLE IF EXISTS outbox;
"#
    .to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn up_migration_creates_table() {
        let sql = generate_outbox_up_migration();
        assert!(sql.contains("CREATE TABLE IF NOT EXISTS outbox"));
        assert!(sql.contains("topic"));
        assert!(sql.contains("partition_key"));
        assert!(sql.contains("payload"));
        assert!(sql.contains("published_at"));
        assert!(sql.contains("CREATE INDEX"));
    }

    #[test]
    fn down_migration_drops_table() {
        let sql = generate_outbox_down_migration();
        assert!(sql.contains("DROP TABLE IF EXISTS outbox"));
        assert!(sql.contains("DROP INDEX IF EXISTS"));
    }
}
